class Solution {
public:
    int minChanges(vector<int>& nums, int k) {
        int n = nums.size();
        int res = n;
        for (int mask = 0; mask < (1 << k); mask++) {
            int cnt = 0;
            for (int i = 0; i < n; i++) {
                if ((nums[i] ^ (mask >> (i % k))) != 0) {
                    cnt++;
                }
            }
            res = min(res, cnt);
        }
        return res;
    }
};
